import xml.etree.ElementTree as ET

def validate_xml(file):
    tree = ET.parse(file)
    root = tree.getroot()
    
    # Validate the XML document by checking if it has a specific tag and attribute
    if root.find('tag') is not None and root.attrib['attribute'] == 'value':
        return True
    else:
        return False